script.text:

function load$CheckingReport$(g) {
  g._$k = [];
  g._$i = g._getColumnOrder('id');
  g._$t = g._getColumnOrder('&Tag;');
  g._$f = 'keys';
  g.add_commandEvent(on$GridReport$ExecuteCommand);
  g.add_onResponseComplete(on$GridReport$ResponseComplete);
}
function dispose$CheckingReport$(g) {
  g._$k = g._$i = g._$t = null;
  try {g.remove_commandEvent(on$GridReport$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridReport$ResponseComplete);} catch (ex) {}
}
function scatter$GridReport$(g) {
  fill$Grid(g, true);
}
function on$GridReport$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'BeforeRemoveRow':
      var k = Array.indexOf(g._$k, g._getItemValue(g._activeRow, g._getColumnOrder('id')));
      if (k != -1) Array.removeAt(g._$k, k);
      break;
    case 'Upload':
      if (&TransferType;== 2) {
        show$Form(g, '&TransferID;Import');
      }
      break;
    case 'Download':
      if (&TransferType;== 1 && g._activeRow > 0) {
        var t0 = g._getItemValue(g._activeRow, g._getColumnOrder('status'));
        if (t0 != '3') {
          var e = g._language == 'v' ? 'Số liệu vẫn chưa được cập nhật.' : 'Data has not been uploaded yet.';
          $message.show(e, String.format('$find(\'{0}\')._activeCell.focus();', g.get_id()));
          break;
        }
        g.showForm('DataCopyDownload');
      }
      break;
    case 'Calculate':
    case 'Register':
    case 'Cancel':
      var s = ',' + g._$k.join(',') + ',';
      if (isCheck$Grid(g)) g.request(g, action, action, [['s', 'Infinite', s]]);
      break;
    case 'ViewCode':
      if (g._activeRow > 0) {
        g._viewID = g._getItemValue(g._activeRow, g._getColumnOrder('id'));
        g.showForm('DataCopyViewCode');
      }
      break;
    default:
      break;
  }
}

function on$GridReport$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object, v = (g._language == 'v');
  var m0 = v ? 'Chương trình đã thực hiện xong.' : 'The process was completed successfully.';
  var m1 = v ? 'Dữ liệu không hợp lệ.' : 'Invalid Data.';
  var m2 = v ? 'Đã khóa số liệu, kiểm tra lại ngày giới hạn hoặc ngày khóa sổ.' : 'Data is locked, you must modify system locked date.';
  if (context == 'Cancel') s = '';
  switch (context) {
    case 'Download':
      var r = $get('requestFormData');
      if (!r) r = $func.requestFormData();
      var query = '?a=1&t=' + '&TransferID;Export' + '&k=' + g._key;
      r.action = $func.resolveClientUrl('~/AppHandler/Transfer.ashx' + query, g._baseUrl);
      if (!$func.isIE) r.target = '_blank';
      r.submit();
      g._key = result[0].Value;
      if (g._activeCell) g._activeCell.focus();
      break;
    case 'Calculate':
    case 'Register':
    case 'Cancel':
      switch (result[0].Value) {
        case 0:
          $message.show(m1);
          break;
        case 2:
          $message.show(m2);
          break;
        default:
          g._$k = [];
          g.goToPage(-1);
          $message.show(m0);
          break;
        }
      break;
    default:
      break;
  }
}

function hiddenToolbars(g) {
  switch (&TransferType;) {
    case 1:
      hiddenToolbarButton(g, ['Upload']);
      break;
    case 2:
      hiddenToolbarButton(g, ['Download', 'New', 'ViewCode']);
      break;
    case 3:
      hiddenToolbarButton(g, ['Upload', 'Download', 'ViewCode']);
      break;
    default:
      break;
  }
  if ('&TransferProcess;' == '1') hiddenToolbarButton(g, ['Cancel', 'Register']);
  if ('&TransferProcess;' == '2') hiddenToolbarButton(g, ['Calculate']);
}
function hiddenToolbarButton(g, a) {
  for (var i = 0; i < a.length; i += 1) {
    for (var j = g._toolbar.length - 1; j >= 0; j--) {
      if (g._toolbar[j][0] == a[i]) Array.removeAt(g._toolbar, j);
    }
  }
}

function request$Download(g, a) {g.request(g, 'Download', a, [['id', 'String', g._getItemValue(g._activeRow, g._getColumnOrder('id'))], ['keyTicket', 'String', g._key]]);}
function show$Form(g, c) {(g._authorize == 1) ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess"));}

function beforeDrillDown$DataCopy(g) {
  if ((g._getItemValue(g._activeRow, g._getColumnOrder('status')) != '2' && g._getItemValue(g._activeRow, g._getColumnOrder('status')) != '3') || !($func.trim(g._getItemValue(g._activeRow, g._activeColumn)))) g._args.cancelEvent = true;
}

      &JavascriptReportInit;
      &ScriptTagReport;

css.text:

div.ViewCode{background-image:url(../Images/Password.png);background-repeat:no-repeat;background-position:0 0;}
div.Calculate{background-image:url(../images/Calculate.png);background-repeat:no-repeat;background-position:0 0;}
div.TextCalculate{background-image:url(../images/TextCalculate.png),url(../images/Line.png);background-repeat:no-repeat,repeat-x;background-position:0 0;}
div.Register{background-image:url(../images/command.png);background-repeat:no-repeat;background-position:0 0;}
div.Cancel{background-image:url(../images/Operation.png);background-repeat:no-repeat;background-position:-22px 0;}
div.Upload{background-image:url(../images/Upload.png);background-repeat:no-repeat;background-position:0 0;}
div.Download{background-image:url(../Images/Download.png);background-repeat:no-repeat;background-position:0 0;}
div.ViewCodeOverGreen, div.CalculateOverGreen, div.TextCalculateOverGreen, div.RegisterOverGreen, div.CancelOverGreen, div.UploadOverGreen, div.DownloadOverGreen{background-position-y:-22px;}
